<?php declare(strict_types=1);
namespace App\Http;
use App\Infrastructure\Container;use App\Middleware\{AuthMiddleware,CsrfMiddleware};
final class Router { private array $routes=[]; public function __construct(private Container $container){} public function add(string $method,string $path,array $action,bool $auth=true):void{$this->routes[$method.$path]=[$action,$auth];} public function dispatch():void{$path=parse_url($_SERVER['REQUEST_URI'],PHP_URL_PATH)?:'/';$key=$_SERVER['REQUEST_METHOD'].$path;if(!isset($this->routes[$key])){http_response_code(404);echo 'Not found';return;}[$action,$auth]=$this->routes[$key];if($auth)$this->container->get(AuthMiddleware::class)->enforce();if($_SERVER['REQUEST_METHOD']==='POST')$this->container->get(CsrfMiddleware::class)->enforce($_POST);[$class,$method]=$action;$this->container->get($class)->$method();} }
